using System;
namespace EduACAS.Testing {
    class Program {
        // Validation logic common to many solutions
        static bool IsValidInput(string s) {
            if (string.IsNullOrWhiteSpace(s)) return false;
            foreach (char c in s) { if (!char.IsDigit(c) && c != '-') return false; }
            return true;
        }

        static void Main(string[] args) {
            try {
                string input1 = Console.ReadLine();
                string input2 = Console.ReadLine();
                if (!IsValidInput(input1) || !IsValidInput(input2)) return;
                int a = int.Parse(input1);
                int b = int.Parse(input2);
                Console.WriteLine(a + b);
            } catch (Exception ex) {
                Console.WriteLine("An error occurred: " + ex.Message);
            }
        }
    }
}

