function bubbleSort(arr: number[]): number[] {
    const n = arr.length;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
            }
        }
    }
    return arr;
}

const sortArray = (list: number[]): number[] => {
    let size = list.length;
    for (let x = 0; x < size; x++) {
        for (let y = 0; y < size - x - 1; y++) {
            if (list[y] > list[y + 1]) {
                let temp = list[y];
                list[y] = list[y + 1];
                list[y + 1] = temp;
            }
        }
    }
    return list;
}

function myBubble(data: number[]) {
    for(var i=0; i<data.length; i++) {
        for(var j=0; j<data.length-i-1; j++) {
            if(data[j] > data[j+1]) {
                var t = data[j];
                data[j] = data[j+1];
                data[j+1] = t;
            }
        }
    }
    return data;
}
